class Solution:
    def interchangeableRectangles(self, rectangles):
        from itertools import combinations
        count = 0
        for (w1, h1), (w2, h2) in combinations(rectangles, 2):
            if w1 * h2 == w2 * h1:
                count += 1
        return count

