class Solution:
    def interchangeableRectangles(self, rectangles):
        from math import gcd
        from collections import Counter
        cnt = Counter()
        for w, h in rectangles:
            g = gcd(w, h)
            cnt[(w // g, h // g)] += 1
        total = 0
        for c in cnt.values():
            total += c * (c - 1) // 2
        return total

