var interchangeableRectangles = function(rectangles) {
    const gcd = (a, b) => { while (b) { [a, b] = [b, a % b]; } return a; };
    const counts = new Map();
    for (const [w, h] of rectangles) {
        const g = gcd(w, h);
        const key = (w / g) + ':' + (h / g);
        counts.set(key, (counts.get(key) || 0) + 1);
    }
    let total = 0;
    for (const c of counts.values()) {
        total += (c * (c - 1)) / 2;
    }
    return total;
};
